def subset_sum(xs, target):
    if target == 0:
        return True
    if not xs:
        return False
    xs = list(set(xs))  # Remove duplicates
    n = len(xs)
    dp = [False] * (target + 1)
    dp[0] = True
    for num in xs:
        for t in range(target, num - 1, -1):
            dp[t] = dp[t] or dp[t - num]
    return dp[target]
